        }
        defer rows.Close()
        for rows.Next() {
                var status string
                var count int
                if err := rows.Scan(&status, &count); err != nil {
                        return nil, err
                }
                switch status {
                case "pending":
                        stats.Pending = count
                case "running":
                        stats.Running = count
                case "completed":
                        stats.Completed = count
                case "failed":
