		j.WorkerID = &wid
	}
	return &j, nil
}

func (s *Service) ListJobs(status string) ([]Job, error) {
	if status != "" && !validJobStatus(status) {
		return nil, fmt.Errorf("%w: invalid status %q", ErrConflict, status)
	}

	var (
		rows *sql.Rows
		err  error
	)
	if status == "" {
		rows, err = s.db.Query(`
			SELECT j.id, j.type, j.payload, j.status, j.priority,
			       j.created_at, j.updated_at, j.worker_id, COALESCE(w.name, '')
			FROM jobs j
			LEFT JOIN workers w ON j.worker_id = w.id
			ORDER BY j.priority DESC, j.created_at ASC
		`)
	} else {
		rows, err = s.db.Query(`
			SELECT j.id, j.type, j.payload, j.status, j.priority,
			       j.created_at, j.updated_at, j.worker_id, COALESCE(w.name, '')
			FROM jobs j
			LEFT JOIN workers w ON j.worker_id = w.id
			WHERE j.status = ?
			ORDER BY j.priority DESC, j.created_at ASC
		`, status)
	}
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var jobs []Job
	for rows.Next() {
		var j Job
		var workerID sql.NullInt64
		if err := rows.Scan(
			&j.ID, &j.Type, &j.Payload, &j.Status, &j.Priority,
			&j.CreatedAt, &j.UpdatedAt, &workerID, &j.WorkerName,
		); err != nil {
			return nil, err
		}
		if workerID.Valid {
			wid := int(workerID.Int64)
			j.WorkerID = &wid
		}
		jobs = append(jobs, j)
	}
	return jobs, rows.Err()
}

func (s *Service) CancelJob(id int) (*Job, error) {
	job, err := s.GetJob(id)
	if err != nil {
		return nil, err
	}
	if job.Status != JobStatusPending {
		return nil, fmt.Errorf("%w: job status is %q", ErrConflict, job.Status)
	}
	if _, err := s.db.Exec(
		"UPDATE jobs SET status=?, updated_at=? WHERE id=?",
		JobStatusCancelled, time.Now(), id,
	); err != nil {
		return nil, err
	}
	return s.GetJob(id)
}

func (s *Service) CompleteJob(id int) (*Job, error) {
	job, err := s.GetJob(id)
	if err != nil {
		return nil, err
	}
	if job.Status != JobStatusRunning {
		return nil, fmt.Errorf("%w: job is not running", ErrConflict)
	}
	if _, err := s.db.Exec(
		"UPDATE jobs SET status=?, updated_at=? WHERE id=?",
		JobStatusCompleted, time.Now(), id,
	); err != nil {
		return nil, err
	}
	return s.GetJob(id)
}

func (s *Service) FailJob(id int) (*Job, error) {
	job, err := s.GetJob(id)
	if err != nil {
		return nil, err
	}
	if job.Status != JobStatusRunning {
		return nil, fmt.Errorf("%w: job is not running", ErrConflict)
	}
	if _, err := s.db.Exec(
		"UPDATE jobs SET status=?, updated_at=? WHERE id=?",
		JobStatusFailed, time.Now(), id,
	); err != nil {
		return nil, err
	}
	return s.GetJob(id)
}

func (s *Service) RegisterWorker(name string) (*Worker, error) {
	if name == "" {
		return nil, fmt.Errorf("name is required")
	}
	res, err := s.db.Exec("INSERT INTO workers (name, status) VALUES (?, ?)", name, WorkerStatusIdle)
	if err != nil {
		return nil, fmt.Errorf("register worker: %w", err)
	}
	id, _ := res.LastInsertId()
	return s.GetWorker(int(id))
}

func (s *Service) GetWorker(id int) (*Worker, error) {
	var w Worker
	err := s.db.QueryRow(
		"SELECT id, name, status, registered_at FROM workers WHERE id=?",
		id,
	).Scan(&w.ID, &w.Name, &w.Status, &w.RegisteredAt)
	if errors.Is(err, sql.ErrNoRows) {
		return nil, ErrNotFound
	}
	return &w, err
}

func (s *Service) ListWorkers() ([]Worker, error) {
	rows, err := s.db.Query("SELECT id, name, status, registered_at FROM workers ORDER BY id")
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var workers []Worker
	for rows.Next() {
		var w Worker
		if err := rows.Scan(&w.ID, &w.Name, &w.Status, &w.RegisteredAt); err != nil {
			return nil, err
		}
		workers = append(workers, w)
	}
	return workers, rows.Err()
}

func (s *Service) GetStats() (*QueueStats, error) {
	// Ensure all fields exist even if counts are zero.
	stats := &QueueStats{}
	rows, err := s.db.Query("SELECT status, COUNT(*) FROM jobs GROUP BY status")
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	for rows.Next() {
		var status string
		var count int
		if err := rows.Scan(&status, &count); err != nil {
			return nil, err
		}
		switch status {
		case JobStatusPending:
			stats.Pending = count
		case JobStatusRunning:
			stats.Running = count
		case JobStatusCompleted:
			stats.Completed = count
		case JobStatusFailed:
			stats.Failed = count
		case JobStatusCancelled:
			stats.Cancelled = count
		}
	}
	return stats, rows.Err()
}
