var (
	ErrNotFound = errors.New("not found")
	ErrConflict = errors.New("conflict")
)

type Service struct {
	db   *sql.DB
	pool *WorkerPool
}

func NewService(db *sql.DB, pool *WorkerPool) *Service {
	return &Service{db: db, pool: pool}
}

func validJobStatus(s string) bool {
	switch s {
	case JobStatusPending, JobStatusRunning, JobStatusCompleted, JobStatusFailed, JobStatusCancelled:
		return true
	default:
		return false
	}
}

func (s *Service) CreateJob(req CreateJobRequest) (*Job, error) {
	if req.Type == "" {
		return nil, fmt.Errorf("type is required")
	}

	res, err := s.db.Exec(
		"INSERT INTO jobs (type, payload, priority, status, worker_id) VALUES (?, ?, ?, ?, NULL)",
		req.Type, req.Payload, req.Priority, JobStatusPending,
	)
	if err != nil {
		return nil, fmt.Errorf("insert job: %w", err)
	}
	id, _ := res.LastInsertId()
	return s.GetJob(int(id))
}

func (s *Service) GetJob(id int) (*Job, error) {
	var j Job
	var workerID sql.NullInt64

	err := s.db.QueryRow(`
		SELECT j.id, j.type, j.payload, j.status, j.priority,
		       j.created_at, j.updated_at, j.worker_id, COALESCE(w.name, '')
		FROM jobs j
		LEFT JOIN workers w ON j.worker_id = w.id
		WHERE j.id = ?
	`, id).Scan(
		&j.ID, &j.Type, &j.Payload, &j.Status, &j.Priority,
		&j.CreatedAt, &j.UpdatedAt, &workerID, &j.WorkerName,
