	if errors.Is(err, sql.ErrNoRows) {
		return nil, ErrNotFound
	}
	if err != nil {
		return nil, err
	}
	if workerID.Valid {
		wid := int(workerID.Int64)
		j.WorkerID = &wid
	}
	return &j, nil
}

